// Normalização robusta para MAVO.AI + WillTalk
const root = $json;
const src = root.body && typeof root.body === 'object' && !Array.isArray(root.body)
  ? { ...root, ...root.body }
  : root;

// Função auxiliar para extrair texto
function toText(v) {
  if (v == null) return '';
  if (typeof v === 'string') return v.trim();
  if (typeof v === 'number' || typeof v === 'boolean') return String(v);
  if (Array.isArray(v)) return v.map(toText).filter(Boolean).join(' ');
  if (typeof v === 'object') {
    if (v.text != null) return toText(v.text);
    if (v.mensagem != null) return toText(v.mensagem);
    if (v.content != null) return toText(v.content);
    if (v.body != null) return toText(v.body);
    return '';
  }
  return String(v);
}

// Extrair nome do cliente
function extractClienteName(obj) {
  if (!obj) return 'Cliente';
  if (typeof obj === 'string') return obj.trim() || 'Cliente';
  if (typeof obj === 'object') {
    return (obj.name || obj.nome || obj.pushName || '').trim() || 'Cliente';
  }
  return 'Cliente';
}

// Extrair telefone
function extractPhone(obj) {
  const phones = [
    obj.cliente_telefone,
    obj.telefone,
    obj.phone,
    obj.phoneNumber,
    obj.contact?.phoneNumber,
    obj.from,
    obj.cliente?.telefone,
    obj.cliente?.phone
  ];

  for (const phone of phones) {
    if (phone) {
      const cleaned = String(phone).replace(/\D/g, '');
      if (cleaned.length >= 8) return cleaned;
    }
  }

  // Fallback: extrair números do nome/string
  if (typeof obj.cliente === 'string') {
    const nums = obj.cliente.replace(/\D/g, '');
    if (nums.length >= 8) return nums;
  }

  throw new Error('Telefone do cliente não encontrado no payload');
}

// Extrair mensagem principal
const mensagem = toText(
  src.mensagem || src.message || src.mensagens || src.messages || src.text || src.body || ''
);

if (!mensagem || mensagem.length < 2) {
  throw new Error('Mensagem muito curta ou vazia');
}

// Extrair ticket ID
const ticket_id = String(
  src.ticket_id || src.ticket?.id || src.conversation_id || src.conversationId || `WT-${Date.now()}`
).trim();

// Extrair dados
const cliente_nome = extractClienteName(src.cliente || src.contact || src.customer);
const cliente_telefone = extractPhone(src);
const canal = src.canal || 'whatsapp';
const tecnico = src.tecnico || src.agent || 'n8n';
const data_evento = src.data_evento || src.timestamp || new Date().toISOString();
const event_id = src.event_id || `evt-${Date.now()}-${Math.random().toString(36).substr(2, 6)}`;

// Log para debug
console.log('📥 Payload normalizado:', {
  ticket_id,
  cliente_nome,
  cliente_telefone: cliente_telefone.substring(0, 4) + '...',
  mensagem_length: mensagem.length,
  canal,
  tecnico
});

return [{
  json: {
    // Para WillTalk triagem
    event_id,
    canal,
    cliente_nome,
    cliente_telefone,
    mensagem,
    ticket_id,

    // Para MAVO.AI ingestão
    ticket_id_mavoai: ticket_id,
    cliente: cliente_nome,
    mensagens: mensagem,
    data_evento,
    tecnico: tecnico,

    // Metadata
    origem: 'n8n',
    timestamp: new Date().toISOString(),
    texto: mensagem
  }
}];

