// Log de sucesso completo
const triageData = $json;
const normalizado = $('2. Normalizar Dados').item.json;
const ingestao = $('5. Ingestão MAVO.AI').item.json;
const respostaIA = $('6. Gerar Resposta IA').item.json;

console.log('✅ Fluxo completo executado:', {
  ticket_id: normalizado.ticket_id,
  cliente: normalizado.cliente_nome,
  triagem_completa: triageData.triageCompleted,
  atendimento_id: ingestao?.atendimento_id,
  resposta_gerada: !!respostaIA
});

return [{
  json: {
    status: 'success',
    message: 'Atendimento processado com sucesso',
    ticket_id: normalizado.ticket_id,
    atendimento_id: ingestao?.atendimento_id,
    resposta_ia: respostaIA,
    timestamp: new Date().toISOString(),
    // Retornar para webhook response
    webhook_response: {
      success: true,
      message: 'Mensagem recebida e processada pelo MAVO.AI',
      atendimento_id: ingestao?.atendimento_id
    }
  }
}];

// Log triagem pendente
const triageData = $json;
const normalizado = $('2. Normalizar Dados').item.json;

console.log('⏳ Triagem pendente:', {
  ticket_id: normalizado.ticket_id,
  cliente: normalizado.cliente_nome,
  action: triageData.action,
  menuAttempts: triageData.menuAttempts
});

return [{
  json: {
    status: 'triagem_pendente',
    message: 'Aguardando triagem do WillTalk',
    ticket_id: normalizado.ticket_id,
    action: triageData.action,
    menuAttempts: triageData.menuAttempts,
    shouldReply: triageData.shouldReply,
    timestamp: new Date().toISOString(),
    // Retornar para webhook response
    webhook_response: {
      success: true,
      message: 'Triagem em andamento no WillTalk',
      status: 'triagem_pendente'
    }
  }
}];

// Tratamento de erros
const error = $input.first().json;
const normalizado = $('2. Normalizar Dados')?.item?.json;

console.error('❌ Erro no fluxo:', {
  error: error.message || error.error || 'Erro desconhecido',
  ticket_id: normalizado?.ticket_id,
  timestamp: new Date().toISOString()
});

return [{
  json: {
    status: 'error',
    message: error.message || 'Erro no processamento',
    ticket_id: normalizado?.ticket_id,
    timestamp: new Date().toISOString(),
    // Retornar para webhook response
    webhook_response: {
      success: false,
      error: error.message || 'Erro no processamento',
      ticket_id: normalizado?.ticket_id
    }
  }
}];
